" --- Service Definition (.srvd) ---
define service ZSD_SalesOrder {
  expose ZI_SalesOrder as SalesOrder;
  expose ZI_SalesItem  as SalesItem;
  expose ZI_Customer   as Customer;
}

" --- Service Binding: created via ADT wizard ---
" ADT > New > Service Binding
" Name: ZSB_SALESORDER_UI
" Binding Type: OData V4 - UI
" Service Definition: ZSD_SalesOrder

" After activation, URL generated:
" /sap/opu/odata4/sap/zsb_salesorder_ui/srvd/sap/zsd_salesorder/0001/

" Test metadata in browser:
" [URL]/$metadata

" Test entity set:
" [URL]/SalesOrder

" --- Fiori Launchpad registration (after Publish) ---
" SPRO > SAP Fiori > Reference Apps > Add Tile
" or via Manage Launchpad Settings app in BTP

" --- Optional: CDS View annotation for Fiori UI ---
@UI.headerInfo: { typeName: 'Sales Order',
                  typeNamePlural: 'Sales Orders' }
@UI.lineItem: [ { position: 10, label: 'Order ID' } ]

followupAnswerBank.codeExample:
" One Service Definition
define service ZSD_SalesOrder {
  expose ZI_SalesOrder as SalesOrder;
}

" Service Binding 1 - Fiori UI
" ZSB_SALESORDER_UI | OData V4 - UI
" URL: /sap/opu/odata4/.../zsb_salesorder_ui/...

" Service Binding 2 - API
" ZSB_SALESORDER_API | OData V4 - Web API
" URL: /sap/opu/odata4/.../zsb_salesorder_api/...

" CDS View with UI annotations
@UI.headerInfo: {
  typeName:       'Sales Order',
  typeNamePlural: 'Sales Orders',
  title:          { value: 'OrderId' },
  description:    { value: 'CustomerId' }
}
define root view entity ZI_SalesOrder ...
{
  @UI.lineItem:       [ { position: 10, label: 'Order ID' } ]
  @UI.selectionField: [ { position: 10 } ]
  key order_id as OrderId,

  @UI.lineItem:       [ { position: 20, label: 'Customer' } ]
  @UI.selectionField: [ { position: 20 } ]
  customer_id  as CustomerId,

  @UI.lineItem: [ { position: 30, label: 'Total Amount' } ]
  total_amount as TotalAmount
}

" CDS View - enable access control
@AccessControl.authorizationCheck: #CHECK
define root view entity ZI_SalesOrder ...

" DCL file (.dcl) - define access policy
@EndUserText.label: 'Sales Order Access Control'
define role ZI_SalesOrder {
  grant select on ZI_SalesOrder
  where (SalesOrg) = aspect pfcg_auth(Z_SO_AUTH,
                                       VKORG, ACTVT = '03');
}

" Transport: include .dcl object in transport request
" Object type: DCLS
" Object name: ZI_SalesOrder

" RAP Business Object = SAP Document concept

" Purchase Order as RAP Business Object:

" Root entity: PO Header
define root view entity ZI_PurchOrder
  as select from ekko
  association [1..*] to ZI_POItem as _Items
    on $projection.EbelnId = _Items.EbelnId
{ key ebeln as EbelnId, lifnr as Vendor, ... }

" Child entity: PO Line Items
define view entity ZI_POItem
  as select from ekpo
{ key ebeln as EbelnId, key ebelp as ItemNo,
  matnr as Material, menge as Quantity, ... }

" BDEF: operations on the object
managed; define behavior for ZI_PurchOrder {
  create; update; delete;
  association _Items { create; }
  validation checkVendor on save { ... }
}
